class AtomicWrite:
    def __init__(self, path):
        self.path = path
        self._tmp = None

    def __enter__(self):
        d = os.path.dirname(self.path) or "."
        self._tmp = tempfile.NamedTemporaryFile("w", dir=d, delete=False)
        return self._tmp

    def __exit__(self, exc_type, *args):
        self._tmp.close()
        if exc_type:
            os.unlink(self._tmp.name)
        else: os.replace(self._tmp.name, self.path)

import threading

class TimedLock:
    def __init__(self, timeout=None):
        self._lock = threading.Lock()
        self._timeout = timeout

    def __enter__(self):
        acquired = self._lock.acquire(timeout=self._timeout or -1)
        if not acquired:
            raise TimeoutError("Could not acquire lock")
        return self

    def __exit__(self, *exc):
        self._lock.release()
        return False

