class AbstractEnforcer(type):
    required_methods = []

    def __new__(mcs, name, bases, namespace):
        cls = super().__new__(mcs, name, bases, namespace)
        if bases:
            missing = [
                m for m in mcs.required_methods
                if m not in namespace or not callable(namespace[m])
            ]
            if missing:
                raise TypeError(
                    f"{name} must implement: {', '.join(missing)}"
                )
        return cls

