class AutoPropertyMeta(type):
    def __new__(mcs, name, bases, namespace):
        annotations = namespace.get("__annotations__", {})
        for attr, attr_type in annotations.items():
            storage = f"_{attr}"
            default = namespace.pop(attr, None)
            namespace[attr] = mcs._make_property(storage, attr_type, default)
        return super().__new__(mcs, name, bases, namespace)

    @staticmethod
    def _make_property(storage, attr_type, default):
        def getter(self):
            return getattr(self, storage, default)
        def setter(self, value):
            if not isinstance(value, attr_type):
                raise TypeError(f"Expected {attr_type.__name__}")
            setattr(self, storage, value)
        return property(getter, setter)

import inspect

class InterfaceMeta(type):
    def __new__(mcs, name, bases, namespace):
        cls = super().__new__(mcs, name, bases, namespace)
        for base in bases:
            if hasattr(base, "_interface_methods"):
                for method_name, sig in base._interface_methods.items():
                    if method_name not in namespace:
                        raise TypeError(
                            f"{name} must implement {method_name}"
                        )
                    impl_sig = inspect.signature(namespace[method_name])
                    if len(impl_sig.parameters) != len(sig.parameters):
                        raise TypeError(
                            f"{name}.{method_name} has wrong signature"
                        )
        return cls

class cached_property:
    def __init__(self, func):
        self.func = func
        self.attrname = func.__name__

    def __set_name__(self, owner, name):
        self.attrname = name

    def __get__(self, instance, owner=None):
        if instance is None:
            return self
        value = self.func(instance)
        setattr(instance, self.attrname, value)
        return value

