class Emitter {
  #events = new Map();

  on(event, fn) {
    if (!this.#events.has(event)) this.#events.set(event, new Set());
    this.#events.get(event).add(fn);
    return () => this.#events.get(event).delete(fn);
  }

  emit(event, ...args) {
    for (const fn of this.#events.get(event) ?? []) fn(...args);
  }

  once(event, fn) {
    const off = this.on(event, (...args) => { off(); fn(...args); });
    return off;
  }
}

