  constructor(subscribe) { this._subscribe = subscribe; }

  subscribe(observer) {
    const obs = typeof observer === 'function' ? { next: observer } : observer;
    const teardown = this._subscribe(obs);
    return { unsubscribe: () => teardown?.() };
  }

  static fromEvent(el, event) {
    return new Observable((obs) => {
      const handler = (e) => obs.next(e);
      el.addEventListener(event, handler);
      return () => el.removeEventListener(event, handler);
    });
  }
}

const EventBus = (() => {
  const listeners = new Map();
  return {
    on(event, fn) {
      if (!listeners.has(event)) listeners.set(event, new Set());
      listeners.get(event).add(fn);
      return () => listeners.get(event).delete(fn);
    },
    emit(event, payload) {
      listeners.get(event)?.forEach((fn) => fn(payload));
      listeners.get('*')?.forEach((fn) => fn(event, payload));
    },
    clear() { listeners.clear(); },
  };
})();

class ChatMediator {
  #users = new Map();

  register(user) {
    this.#users.set(user.name, user);
    user.mediator = this;
  }

  send(from, to, msg) {
    const r = this.#users.get(to);
    if (!r) throw new Error(`User ${to} not found`);
    r.receive(from, msg);
  }

  broadcast(from, msg) {
    for (const [name, user] of this.#users) if (name !== from) user.receive(from, msg);
  }
}

const createStore = (initial) => {
  let state = structuredClone(initial);
  const listeners = new Set();
  return {
    getState: () => state,
    setState(updater) {
      const next = typeof updater === 'function' ? updater(state) : updater;
      if (next !== state) { state = next; listeners.forEach((fn) => fn(state)); }
    },
    subscribe(fn) {
      listeners.add(fn);
      return () => listeners.delete(fn);
    },
  };
};

