class Maybe {
  constructor(value) { this._value = value; }
  static of(value) { return new Maybe(value); }
  isNothing() { return this._value == null; }
  map(fn) { return this.isNothing() ? this : Maybe.of(fn(this._value)); }
  flatMap(fn) { return this.isNothing() ? this : fn(this._value); }
  getOrElse(fallback) { return this.isNothing() ? fallback : this._value; }
}

