class Either {
  constructor(left, right) { this.left = left; this.right = right; }
  static right(v) { return new Either(null, v); }
  static left(v) { return new Either(v, null); }
  isLeft() { return this.left !== null; }

  map(fn) { return this.isLeft() ? this : Either.right(fn(this.right)); }
  flatMap(fn) { return this.isLeft() ? this : fn(this.right); }
  fold(onLeft, onRight) { return this.isLeft() ? onLeft(this.left) : onRight(this.right); }
}

const parseJSON = (str) => {
