const withCache = (target, ttl = 60_000) => {
  const cache = new Map();
  return new Proxy(target, {
    get(obj, prop) {
      const val = Reflect.get(obj, prop);
      if (typeof val !== 'function') return val;
      return (...args) => {
        const key = `${prop}:${JSON.stringify(args)}`;
        const cached = cache.get(key);
        if (cached && Date.now() - cached.ts < ttl) return cached.value;
        const result = val.apply(obj, args);
        cache.set(key, { value: result, ts: Date.now() });
        return result;
      };
    },
  });
};

const reactive = (target, onChange) => new Proxy(target, {
  get(obj, prop) {
    const val = Reflect.get(obj, prop);
    return typeof val === 'object' && val !== null ? reactive(val, onChange) : val;
  },
  set(obj, prop, value) {
    const old = obj[prop];
    const result = Reflect.set(obj, prop, value);
    if (old !== value) onChange(prop, value, old);
    return result;
  },
  deleteProperty(obj, prop) {
    const result = Reflect.deleteProperty(obj, prop);
    onChange(prop, undefined);
    return result;
  },
});

const immutable = (obj) => new Proxy(obj, {
  get(target, prop) {
    const val = Reflect.get(target, prop);
    return typeof val === 'object' && val !== null ? immutable(val) : val;
  },
  set(_, prop) {
    throw new TypeError(`Cannot set '${prop}' on immutable object`);
  },
  deleteProperty(_, prop) {
    throw new TypeError(`Cannot delete '${prop}' from immutable object`);
  },
  defineProperty(_, prop) {
    throw new TypeError(`Cannot define '${prop}' on immutable object`);
  },
});

const withAccess = (target, role, permissions) => new Proxy(target, {
  get(obj, prop) {
    const allowed = permissions[role];
    if (allowed && !allowed.read.includes(prop) && !allowed.read.includes('*')) {
      throw new Error(`Role '${role}' cannot read '${prop}'`);
    }
    return Reflect.get(obj, prop);
  },
  set(obj, prop, value) {
    const allowed = permissions[role];
    if (allowed && !allowed.write.includes(prop)) {
      throw new Error(`Role '${role}' cannot write '${prop}'`);
    }
    return Reflect.set(obj, prop, value);
  },
});

const withDefaults = (target, defaults) => new Proxy(target, {
  get(obj, prop) {
    if (prop in obj) return Reflect.get(obj, prop);
    return prop in defaults ? defaults[prop] : undefined;
  },
  has(obj, prop) {
    return prop in obj || prop in defaults;
  },
});

