type Transition<S extends string, E extends string> =
  { from: S; event: E; to: S };

class StateMachine<S extends string, E extends string> {
  constructor(private state: S, private transitions: Transition<S, E>[]) {}

  send(event: E): S {
    const t = this.transitions.find(
      (tr) => tr.from === this.state && tr.event === event
    );
    if (!t) throw new Error(`No transition for ${event}`);
    this.state = t.to;
    return this.state;
  }
}

