type Schema = Record<string, (v: any) => boolean>;

function Validate(schema: Schema) {
  return (_t: any, _k: string, desc: PropertyDescriptor) => {
    const original = desc.value;
    desc.value = function (input: Record<string, any>) {
      for (const [field, check] of Object.entries(schema)) {
        if (!check(input[field])) throw new Error(`Invalid: ${field}`);
      }
      return original.call(this, input);
    };
  };
}

