@Target(ElementType.METHOD)
@Retention(RetentionPolicy.RUNTIME)
public @interface RateLimit {
    int maxCalls() default 100;
}

@Aspect
@Component
public class RateLimitAspect {
    private final Map<String, AtomicInteger> counters = new ConcurrentHashMap<>();

    @Around("@annotation(limit)")
    public Object enforce(ProceedingJoinPoint pjp, RateLimit limit) throws Throwable {
        int c = counters.computeIfAbsent(pjp.getSignature().toShortString(), k -> new AtomicInteger()).incrementAndGet();
        if (c > limit.maxCalls()) throw new ResponseStatusException(HttpStatus.TOO_MANY_REQUESTS);
        return pjp.proceed();
    }
}

