public class BoundedBuffer<T> {
    private final Queue<T> queue = new LinkedList<>();
    private final int capacity;
    public BoundedBuffer(int capacity) { this.capacity = capacity; }

    public synchronized void put(T item) throws InterruptedException {
        while (queue.size() == capacity) wait();
        queue.add(item);
        notifyAll();
    }

    public synchronized T take() throws InterruptedException {
        while (queue.isEmpty()) wait();
        T item = queue.poll();
        notifyAll();
        return item;
    }
}

public class CachedConfig {
    private final ReadWriteLock lock = new ReentrantReadWriteLock();
    private final Map<String, String> config = new HashMap<>();

    public String get(String key) {
        lock.readLock().lock();
        try { return config.get(key); }
        finally { lock.readLock().unlock(); }
    }

    public void put(String key, String value) {
        lock.writeLock().lock();
        try { config.put(key, value); }
        finally { lock.writeLock().unlock(); }
    }
}

public class ServiceStartup {

    public void startAll(List<Runnable> services) throws InterruptedException {
        CountDownLatch latch = new CountDownLatch(services.size());
        ExecutorService exec = Executors.newFixedThreadPool(services.size());
        for (Runnable svc : services) {
            exec.submit(() -> {
                try { svc.run(); }
                finally { latch.countDown(); }
            });
        }
        boolean ready = latch.await(30, TimeUnit.SECONDS);
        System.out.println(ready ? "All started" : "Timed out");
        exec.shutdown();
    }
}

public class ConnectionPool {
    private final Semaphore semaphore;
    private final Queue<Connection> pool = new ConcurrentLinkedQueue<>();

    public ConnectionPool(int max) {
        this.semaphore = new Semaphore(max);
        for (int i = 0; i < max; i++) pool.add(createConnection());
    }

    public Connection acquire() throws InterruptedException {
        semaphore.acquire();
        return pool.poll();
    }

    public void release(Connection c) { pool.offer(c); semaphore.release(); }

    private Connection createConnection() { return new Connection(); }
}

