func fanOut(jobs <-chan int, workers int) <-chan int {
	results := make(chan int)
	var wg sync.WaitGroup
	for i := 0; i < workers; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			for j := range jobs {
				results <- j * j
			}
		}()
	}
	go func() {
		wg.Wait()
		close(results)
	}()
	return results
}

func fetchWithTimeout(ch <-chan string, timeout time.Duration) (string, error) {
	select {
	case result := <-ch:
		return result, nil
	case <-time.After(timeout):
		return "", fmt.Errorf("timed out after %v", timeout)
	}
}

