func processAll(items []string, maxConcurrent int) {
	sem := make(chan struct{}, maxConcurrent)
	var wg sync.WaitGroup
	for _, item := range items {
		wg.Add(1)
		sem <- struct{}{}
		go func(s string) {
			defer wg.Done()
			defer func() { <-sem }()
			process(s)
		}(item)
	}
	wg.Wait()
}

func first(queries ...func() string) string {
	ch := make(chan string, len(queries))
	for _, q := range queries {
