    while let Some(msg) = rx.recv().await { println!("Got: {}", msg); }
}

async fn run() {
    let (tx, rx) = mpsc::channel(32);
    tokio::spawn(producer(tx));
    consumer(rx).await;
}

use tokio_stream::StreamExt;

async fn process_events(mut stream: impl StreamExt<Item = Event> + Unpin) {
    while let Some(event) = stream.next().await {
        match event {
            Event::Data(d) => println!("data: {}", d),
            Event::Error(e) => eprintln!("error: {}", e),
            Event::Done => break,
        }
    }
}

use std::sync::Arc;
use tokio::sync::Mutex;

struct AppState {
    cache: Arc<Mutex<HashMap<String, String>>>,
}

impl AppState {
    async fn get(&self, key: &str) -> Option<String> {
        let cache = self.cache.lock().await;
        cache.get(key).cloned()
    }

    async fn set(&self, key: String, value: String) {
        let mut cache = self.cache.lock().await;
        cache.insert(key, value);
    }
}

use tokio::signal;

async fn run_server() {
    let listener = TcpListener::bind("0.0.0.0:8080").await.unwrap();
    loop {
        tokio::select! {
            Ok((socket, _)) = listener.accept() => {
                tokio::spawn(handle_connection(socket));
            }
            _ = signal::ctrl_c() => {
                println!("Shutting down gracefully...");
                break;
            }
        }
    }
}

use tokio::time::{sleep, Duration};

async fn retry<F, Fut, T, E>(mut f: F, max: u32) -> Result<T, E>
where F: FnMut() -> Fut, Fut: Future<Output = Result<T, E>>,
{
    let mut attempt = 0;
    loop {
        match f().await {
            Ok(val) => return Ok(val),
            Err(e) if attempt >= max => return Err(e),
            Err(_) => {
                sleep(Duration::from_millis(100 << attempt)).await;
                attempt += 1;
            }
        }
    }
}
